export default "/* inlined from ../_variables.css */\n:host {\n  --theme-bg: hsl(0 0% 100%);\n  --theme-bd: hsl(0 0% 100% / .8);\n  --theme-bd-2: hsl(0 0% 100% / .9);\n  --theme-color: hotpink;\n  --theme-blue: hsl(188 90% 45%);\n  --theme-purple: hsl(267 100% 58%);\n\n  --theme-text_color: hsl(0 0% 10%);\n  --theme-icon_color: hsl(0 0% 20%);\n  --theme-icon_hover-bg: hsl(0 0% 95%);\n  --theme-icon_active-bg: hsl(0 0% 90%);\n\n  --layer-top: 2147483647;\n  --layer-1: 2147483646;\n  --layer-2: 2147483645;\n  --layer-3: 2147483644;\n  --layer-4: 2147483643;\n  --layer-5: 2147483642;\n\n  @media (prefers-color-scheme: dark) {\n    --theme-bg: hsl(0 0% 10%);\n    --theme-bd: hsl(0 0% 10% / .8);\n    --theme-bd-2: hsl(0 0% 10% / .9);\n\n    --theme-text_color: hsl(0 0% 80%);\n    --theme-icon_color: hsl(0 0% 60%);\n    --theme-icon_hover-bg: hsl(0 0% 15%);\n    --theme-icon_active-bg: hsl(0 0% 20%);\n  }\n}\n\n\n:host {\n  font-size: 16px;\n\n  --top: 0;\n  --left: 0;\n  --max-width: 0;\n  --translate-x: 0px;\n  --stack-offset-y: 0px;\n  --translate-y: calc(-100% - var(--stack-offset-y));\n}\n\n:host > span.label-shell {\n  position: fixed;\n  top: var(--top);\n  left: var(--left);\n  max-width: var(--max-width);\n  z-index: var(--layer-4);\n  transform: translateX(var(--translate-x)) translateY(var(--translate-y));\n  background: var(--label-bg, hotpink);\n  border-radius: 0.2em 0.2em 0 0;\n  text-shadow: 0 0.5px 0 hsla(0, 0%, 0%, 0.4);\n  color: white;\n  display: inline-flex;\n  align-items: center;\n  gap: 6px;\n  justify-content: center;\n  font-size: 0.8em;\n  font-weight: normal;\n  font-family: system-ui, -apple-system, Segoe UI, Roboto, Ubuntu, Cantarell, Noto Sans, sans-serif;\n  white-space: nowrap;\n  padding: 0.25em 0.4em 0.15em;\n  line-height: 1.1;\n}\n\n:host([data-edge-attached-label=\"true\"]) > span.label-shell {\n  transform: translateX(var(--translate-x)) translateY(calc(-100% + 1px));\n}\n\n:host([data-inside-label=\"true\"]) > span.label-shell {\n  border-radius: 0 0 0.2em 0.2em;\n}\n\n.label-text {\n  flex: 1 1 auto;\n  display: inline-flex;\n  gap: 2px;\n  min-width: 0;\n  overflow: hidden;\n}\n\n:host a {\n  text-decoration: none;\n  color: inherit;\n  cursor: pointer;\n  text-overflow: ellipsis;\n  overflow: hidden;\n\n  &:hover {\n    text-decoration: underline;\n    color: white;\n  }\n\n  &[node]:before {\n    content: \"\\003c\";\n  }\n\n  &[node]:after {\n    content: \"\\003e\";\n  }\n}\n\nbutton[data-action] {\n  flex: 0 0 auto;\n  border: 0;\n  border-radius: 999px;\n  padding: 0.1em 0.5em;\n  background: hsl(0 0% 100% / 0.18);\n  color: inherit;\n  font: inherit;\n  cursor: pointer;\n}\n";
